import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import "../index.css";

const API_BASE = "http://localhost:5000/api/products";

function ProductDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);

  // Fetch product by ID
  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const res = await axios.get(`${API_BASE}/${id}`);
        setProduct(res.data);
      } catch (err) {
        console.error("Error fetching product:", err);
        alert("❌ Failed to load product details");
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  if (loading) return <h2 style={{ textAlign: "center" }}>Loading...</h2>;
  if (!product)
    return <h2 style={{ textAlign: "center" }}>Product not found ❌</h2>;

  const handleBuyNow = () => {
    alert("✅ Redirecting to checkout...");
    navigate("/checkout", { state: { product } });
  };

  const handleAddToCart = () => {
    let cart = JSON.parse(localStorage.getItem("cart")) || [];
    const exists = cart.find((item) => item._id === product._id);

    if (exists) {
      alert("🛒 Already in cart!");
    } else {
      cart.push(product);
      localStorage.setItem("cart", JSON.stringify(cart));
      alert("✅ Added to cart!");
    }
  };

  return (
    <div className="product-details-container">
      <div className="product-details-card">
        {/* Image Section */}
        <div className="product-image-section">
          <img src={product.image} alt={product.name} className="product-image" />
        </div>

        {/* Info Section */}
        <div className="product-info-section">
          <h2>{product.name}</h2>
          <p className="category">📂 {product.category}</p>

          <div className="price-section">
            <h3>₹{product.price}</h3>
            {product.offerPrice && (
              <span className="offer-price">Offer: ₹{product.offerPrice}</span>
            )}
          </div>

          <p className="desc">{product.description}</p>

          {/* 🆕 Extra details for second-hand gadgets */}
          <div className="extra-info">
            <p>🗓️ Purchase Year: {product.purchaseYear || "N/A"}</p>
            <p>🛡️ Warranty: {product.warranty || "N/A"}</p>
            <p>💎 Condition: {product.condition || "N/A"}</p>
          </div>

          <div className="button-group">
            <button className="btn-buy" onClick={handleBuyNow}>
              🛍️ Buy Now
            </button>
            <button className="btn-cart" onClick={handleAddToCart}>
              ➕ Add to Cart
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ProductDetails;
